import java.lang.StringBuilder
import java.util.Map
import java.sql.PreparedStatement
import java.sql.ResultSetMetaData
import org.postgresql.util.PGobject
import org.postgresql.util.PSQLException
import org.apache.nifi.components.state.Scope
import org.apache.nifi.controller.ControllerService
import groovy.transform.Field
import groovy.sql.Sql
import groovy.json.JsonSlurper

@Field JsonSlurper parser = new JsonSlurper()

@Field Map config

@Field var flowFile

@Field var schema
@Field var root
@Field var targets
@Field var filterkey
@Field var filter
@Field var select
@Field var statekey
@Field var statemap
@Field var state
@Field var refMin
@Field var refMax
@Field var srcconn
@Field var srcsql

flowFile = session.get()

if (!flowFile) {
  return
}


state = context.getStateManager().getState(Scope.CLUSTER)
statemap = new HashMap(state.toMap())

config = parser.parseText(data_migration_config.value)

schema = flowFile.getAttribute("migration.schema")
root = flowFile.getAttribute("migration.root")
targets = parser.parseText(flowFile.getAttribute("migration.targets"))
filterkey = flowFile.getAttribute("migration.filter")
filter = config.filters[filterkey]

statekey = filterkey + ":" + root
refMin = statemap.get(statekey) ?: flowFile.getAttribute("migration.ref")
refMax = refMin

select = config.select.default

var selectkey = schema + "." + root

if (config.select[selectkey]) {
  var override = config.select[selectkey]
  if (override.lookahead) {
    select.lookahead = override.lookahead
  }
  if (override.limit) {
    select.limit = override.limit
  }
}

if (!filter) {
  log.error("unknown filter {}", filterkey)
  flowFile = session.penalize(flowFile)
  session.transfer(flowFile, REL_FAILURE)
  return
}

if (!filter.active) {
  log.error("inactive filter {}", filterkey)
  flowFile = session.penalize(flowFile)
  session.transfer(flowFile, REL_FAILURE)
  return
}

def processFilter() {
  var targetCTEs = [""]
  var targetCountSums = ["1"]
  var targetCountJoins = ["from ids"]
  var targetCounts = ["id"]

  for (var target in targets) {
    if(target.equals(root)) {
      continue
    }

    targetCTEs.add(
      """
      ${target}_counts as (
        select
          nested.parent_id,
          count(*)
        from ids
        join ${schema}.${target} as nested on
          nested.parent_id = ids.id
        group by parent_id
      )
      """.toString().stripIndent(4).trim()
    )

    targetCountSums.add("coalesce(${target}_counts.count, 0)".toString())
    targetCountJoins.add("${target}_counts on ${target}_counts.parent_id = ids.id".toString())
    targetCounts.add(target)
  }

  var q = """
  with
  ids as (
    select
      id from ${schema}.${root} as root
    where
      ${filter.filter} and id > '${refMin}'
    limit ${select.lookahead}
  )${targetCTEs.join(",\n  ")},
  counts as (
    select
      ids.id,
      sum(${targetCountSums.join(" + ")}) over (order by id) as rows
    ${targetCountJoins.join("\n    left join ")}
  ),
   lagged as (
    select
      id,
      lag(rows, 1, 0) over (order by id) as rows
    from counts
  )
  select max(id::text) from lagged where rows < ${select.limit}
  """.toString().stripIndent(2)

  try {
    srcsql.eachRow(q) { row ->
      if (!row.max) {
        return
      }

      refMax = row.max

      var dataf = session.create(flowFile)
      dataf = session.putAttribute(dataf, "migration.ref.min", refMin)
      dataf = session.putAttribute(dataf, "migration.ref.max", refMax)
      dataf = session.putAttribute(dataf, "migration.kind", "data")
      session.transfer(dataf, REL_SUCCESS)

      var loopf = session.create(flowFile)
      loopf = session.putAttribute(loopf, "migration.ref", refMax)
      loopf = session.putAttribute(loopf, "migration.kind", "loop")
      session.transfer(loopf, REL_SUCCESS)
    }
  } catch (e) {
    log.error("executing {}", q, e)
    throw e
  }

  statemap.put(statekey, refMax)

  while (!context.getStateManager().replace(state, statemap, Scope.CLUSTER)) {
    state = context.getStateManager().getState(Scope.CLUSTER)
    statemap = new HashMap(state.toMap())
    statemap.put(statekey, refMax)
  }
}

var lookup = context.controllerServiceLookup
var srcsvcid = lookup.getControllerServiceIdentifiers(ControllerService).find {
  cs -> lookup.getControllerServiceName(cs) == "postgres_source"
}

try {
  srcconn = lookup.getControllerService(srcsvcid).getConnection()
  srcsql = new Sql(srcconn);

  processFilter()

  session.remove(flowFile)
} catch (e) {
  log.error("Script error when processing filter {} for {} in range {} ~ {}", filterkey, root, refMin, refMax, e)
  flowFile = session.penalize(flowFile)
  session.transfer(flowFile, REL_FAILURE)
} finally {
  srcsql?.close()
  srcconn?.close()
}

