targets = parser.parseText(flowFile.getAttribute("migration.targets"))
filterkey = flowFile.getAttribute("migration.filter")
filter = config.filters[filterkey]

refMin = flowFile.getAttribute("migration.ref.min")
refMax = flowFile.getAttribute("migration.ref.max")

select = config.select.default

var selectkey = schema + "." + root

if (config.select[selectkey]) {
  var override = config.select[selectkey]
  if (override.lookahead) {
    select.lookahead = override.lookahead
  }
  if (override.limit) {
    select.limit = override.limit
  }
}

if (!filter) {
  log.error("unknown filter {}", filterkey)
  flowFile = session.penalize(flowFile)
