if (!filter.active) {
  log.error("inactive filter {}", filterkey)
  flowFile = session.penalize(flowFile)
  session.transfer(flowFile, REL_FAILURE)
  return
}

def processFilter() {
  var results = []
  var roots = [:]
  Set unreferenced = []

  SQL.source.eachRow(
    """
    select
      root.id,
      to_jsonb(root.*) as entry
    from ${schema}.${root} as root where
      ${filter.filter} and id > '${refMin}' and id <= '${refMax}'
    """.toString()
  ) { row ->
    roots[row.id] = parser.parseText(row.entry.toString())
    unreferenced.add(row.id)
  }

  var current

  for (var target in targets) {
    if (target.equals(root)) {
      continue
    }

    SQL.source.eachRow(
      """
      select
        nested.parent_id,
        to_jsonb(nested.*) as entry
      from ${schema}.${root} as root
      join ${schema}.${target} as nested on
        nested.parent_id = root.id and
        ${filter.filter} and
        root.id > '${refMin}' and
        root.id <= '${refMax}'
      """.toString()
    ) { row ->
      if (!current || total >= select.limit) {
        if (current) {
          results.addAll(current)
        }

        current = [:].withDefault { k ->
          unreferenced.remove(k)
          return ["root": roots[k]].withDefault { nk -> [] }
        }

        total = 0
      }

      current[row.parent_id][target].add(parser.parseText(row.entry.toString()))
      total++
    }
  }

  if (!current) {
    current = [:].withDefault{ k -> ["root":roots[k]] }
  }

  for (var id in unreferenced.clone()) {
    current[id]
  }

  if (current && current.size() > 0) {
    results.add(current)
  }

  for (var result : results) {
    var f = session.create(flowFile)
    f = session.putAttribute(f, "mime.type", "application/json")
    session.write(
      f,
      (OutputStreamCallback) (    
        o -> o.write(writer.toJson(result.values()).getBytes())
      )
    )
    session.transfer(f, REL_SUCCESS)
  }
}


try {
  processFilter()

  session.remove(flowFile)
} catch (e) {
  log.error("Script error when processing filter {} for {} in range {} ~ {}", filterkey, root, refMin, refMax, e)
  flowFile = session.penalize(flowFile)
  session.transfer(flowFile, REL_FAILURE)
}

import java.lang.StringBuilder
import java.sql.PreparedStatement
import java.sql.ResultSetMetaData
import org.postgresql.util.PGobject
import org.postgresql.util.PSQLException
import java.util.Map
import groovy.transform.Field
import groovy.sql.Sql
import groovy.json.JsonSlurper
import groovy.json.JsonOutput


@Field JsonSlurper parser = new JsonSlurper()
@Field JsonOutput writer = new JsonOutput()

@Field Map config

@Field var flowFile

@Field var schema
@Field var root
@Field var targets
@Field var filterkey
@Field var filter
@Field var insert

flowFile = session.get()

if (!flowFile) {
  return
}


config = parser.parseText(data_migration_config.value)

schema = flowFile.getAttribute("migration.schema")
root = flowFile.getAttribute("migration.root")
targets = parser.parseText(flowFile.getAttribute("migration.targets"))
filterkey = flowFile.getAttribute("migration.filter")
filter = config.filters[filterkey]
insert = config.insert

if (!filter) {
  log.error("unknown filter {}", filterkey)
  flowFile = session.penalize(flowFile)
  session.transfer(flowFile, REL_FAILURE)
  return
}

if (!filter.active) {
  log.error("inactive filter {}", filterkey)
  flowFile = session.penalize(flowFile)
  session.transfer(flowFile, REL_FAILURE)
  return
}

def processFilter(rows, attempt) {
  var excludes = [:]
  var columns = [:]

  SQL.target.eachRow(
    """
    select
      table_name,
      string_agg(column_name || ' = excluded.' || column_name, E',\\n    ') filter (where column_name not in ('id', 'parent_id')) as exclude,
      string_agg(column_name, ',') as columns
    from information_schema.columns where
      table_schema = '${schema}' and
      table_name = any('{${targets.join(",")}}') and
      is_generated != 'ALWAYS' and
      is_generated != 'NO'
    group by table_name
    """.toString()
  ) { row ->
    excludes[row.table_name] = row.exclude
    columns[row.table_name] = row.columns
  }

  var statements = []

  statements.add(
    """
    ${root}_data as (
      select (jsonb_populate_record(null::${schema}.${root}, (select data->'root'))).* from rowdata
    ),
    ${root} as (
      insert into ${schema}.${root}(${columns[root]})
      select ${columns[root]} from ${root}_data
      on conflict(id) do update set
        ${excludes[root]}
    )
    """.toString().stripIndent().trim()
  )

  for (var target in targets) {
    if (target.equals(root)) {
      continue
    }

    statements.add(
      """
      ${target}_data as (
        select (jsonb_populate_recordset(null::${schema}.${target}, coalesce((select data->'${target}'), '[]'))).* from rowdata
      ),
      ${target} as (
        insert into ${schema}.${target}(${columns[target]})
        select ${columns[target]} from ${target}_data
        on conflict(id) do update set
          ${excludes[target]}
      )
      """.toString().stripIndent().trim()
    )
  }

  var q = """
  with
  batch(data) as (
    select cast(? as jsonb)
  ),
  rowdata(data) as (
    select jsonb_array_elements(data) from batch
  ),
  ${statements.join(",")}
  select 1
  """.toString()

  try {
    SQL.target.execute(q, [rows]) 
  } catch (e) {
    log.error("error executing {}", q, e)
    flowFile = session.putAttribute(flowFile, "migration.attempt", (attempt+1).toString())
    throw e
  }
}


var attempt
var rows
var parsed

try {
  ByteArrayOutputStream bs = new ByteArrayOutputStream()
  session.exportTo(flowFile, bs)

  rows = bs.toString()

  attempt = Integer.parseInt(flowFile.getAttribute("migration.attempt") ?: "0")

  if ("true".equals(flowFile.getAttribute("migration.reset_id"))) {
    parsed = parser.parseText(rows)
    var res = SQL.target.firstRow("select public.ulid_generate() as id, now() at time zone 'utc' as now")
    log.warn("Correcting bogus id for {}.{}: {} ({}) -> {} ({})", schema, root, parsed[0].root.id, parsed[0].root.created_date, res.id, res.now)
    parsed[0].root.id = res.id
    parsed[0].root.created_date = res.now
    for (entry in parsed[0]) {
      if (entry.key.equals("root")) {
        continue
      }
      for (var v in entry.value) {
        v.parent_id = res.id
      }
    }
    rows = writer.toJson(parsed)
  }

  processFilter(rows, attempt)

  //session.remove(flowFile)
  session.transfer(flowFile, REL_SUCCESS)
} catch (e) {
  var skip = false
  var resetid = false

  if (e instanceof org.postgresql.util.PSQLException) {
    if (e.getServerErrorMessage() != null) {
      var hint = (e.getServerErrorMessage().getHint() ?: "").toString()
      if (insert.skip_obsolete_dictionaries && "dict_has_newer_record".equals(hint)) {
        log.warn("Obsolete dictionary entry skipped", e)
        skip = true
      } else if (insert.correct_bogus_ids && hint.startsWith("Either issue new id")) {
        resetid = true
      }
    }
  }

  log.error("Script error when processing filter {} for {} (attempt {})", filterkey, root, attempt, e)

  if ((attempt >= insert.attempts || resetid) && insert.split) {
    if (!parsed) {
      parsed = parser.parseText(rows)
    }

    if (parsed.size() > 1) {
      if (resetid) {
        for (var el : parsed) {
          var f = session.create(flowFile)
          f = session.putAttribute(f, "migration.attempt", "0")
          session.write(f, (OutputStreamCallback) (o -> o.write(writer.toJson([el]).getBytes())))
          f = session.penalize(f)
          session.transfer(f, REL_FAILURE)
        }

        session.remove(flowFile)

        return
      }

      var a = parsed.subList(0, parsed.size().intdiv(2))
      var b = parsed.subList(parsed.size().intdiv(2), parsed.size())

      var fa = session.create(flowFile)
      //fa = session.putAttribute(fa, "migration.attempt", "0")
      session.write(fa, (OutputStreamCallback) (o -> o.write(writer.toJson(a).getBytes())))
      fa = session.penalize(fa)
      session.transfer(fa, REL_FAILURE)

      var fb = session.create(flowFile)
      //fb = session.putAttribute(fb, "migration.attempt", "0")
      session.write(fb, (OutputStreamCallback) (o -> o.write(writer.toJson(b).getBytes())))
      fb = session.penalize(fb)
      session.transfer(fb, REL_FAILURE)

      session.remove(flowFile)

      return 
    } else if (parsed.size() == 1 && resetid) {
      flowFile = session.putAttribute(flowFile, "migration.reset_id", "true")
    }
  }

  if (skip) {
    session.remove(flowFile)
    return
  }

  flowFile = session.penalize(flowFile)
  session.transfer(flowFile, REL_FAILURE)
}

